#if UNITY_EDITOR
using UnityEditor;
using UnityEngine;

/// <summary>
/// Editor customizado do EnemyHealth (Etapa 8.3): desenha a lista
/// [SerializeReference] "vulnerabilityConditions" (janela de vulnerabilidade)
/// com o PolymorphicListDrawer — mesmo padrão das condições de desactivação
/// no EnemyControllerEditor.
/// </summary>
[CustomEditor(typeof(EnemyHealth))]
public class EnemyHealthEditor : Editor
{
    private SerializedProperty _vulnerabilityConditionsProp;

    private void OnEnable()
    {
        _vulnerabilityConditionsProp = serializedObject.FindProperty("vulnerabilityConditions");
    }

    public override void OnInspectorGUI()
    {
        serializedObject.Update();

        DrawPropertiesExcluding(serializedObject, "m_Script", "vulnerabilityConditions");

        EditorGUILayout.Space();
        PolymorphicListDrawer.Draw(serializedObject, _vulnerabilityConditionsProp, "Janela de Vulnerabilidade (Etapa 8.3)", typeof(EnemyCondition), "Adicionar Condição de Vulnerabilidade");

        serializedObject.ApplyModifiedProperties();
    }
}
#endif
